1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type DamageEntry = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: DamageEntry[] };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	type QuoteResult = { premium: number };
10	type ClaimResult = { payout: number; remainingCap: number };
11	type StepResult = QuoteResult | ClaimResult;
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const LOYALTY_THRESHOLD_YEARS = 2;
20	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
21	const DEDUCTIBLE = 100;
22	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
23	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	const INSURANCE_VALUES: Record<string, number> = {
33	  sword: 1000,
34	  amulet: 600,
35	  staff: 800,
36	  potion: 400,
37	  rune: 250,
38	  moonstone: 250,
39	};
40	
41	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
42	const BLOCK_SIZE = 3;
43	const BLOCK_BASE_PREMIUM = 60;
44	
45	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUMS;
46	
47	const assertKnownItemType = (type: string): void => {
48	  if (!isKnownItemType(type)) throw new Error(`Unknown item type: ${type}`);
49	};
50	
51	const unitBasePremium = (type: string): number => BASE_PREMIUMS[type] ?? 0;
52	
53	const unitInsuranceValue = (type: string): number => INSURANCE_VALUES[type] ?? 0;
54	
55	const isComponentBlock = (type: string, count: number): boolean =>
56	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
57	
58	const groupBasePremium = (type: string, count: number): number =>
59	  isComponentBlock(type, count) ? BLOCK_BASE_PREMIUM : count * unitBasePremium(type);
60	
61	const countBy = <T>(values: T[], key: (value: T) => string): Map<string, number> =>
62	  values.reduce(
63	    (counts, value) => counts.set(key(value), (counts.get(key(value)) ?? 0) + 1),
64	    new Map<string, number>(),
65	  );
66	
67	const countByType = (items: Item[]): Map<string, number> =>
68	  countBy(items, (item) => item.type);
69	
70	const itemsBasePremium = (items: Item[]): number =>
71	  [...countByType(items)].reduce(
72	    (total, [type, count]) => total + groupBasePremium(type, count),
73	    0,
74	  );
75	
76	const enchantmentLevel = (item: Item | undefined): number => item?.enchantment ?? 0;
77	
78	const itemModifierSurcharge = (item: Item): number => {
79	  const base = unitBasePremium(item.type);
80	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
81	  const highEnchantmentSurcharge =
82	    enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
83	  return curseSurcharge + highEnchantmentSurcharge;
84	};
85	
86	const itemsModifierSurcharge = (items: Item[]): number =>
87	  items.reduce((total, item) => total + itemModifierSurcharge(item), 0);
88	
89	const loyaltyDiscount = (base: number, customer: Customer): number =>
90	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
91	
92	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
93	  isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
94	
95	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
96	  const base = itemsBasePremium(items);
97	  const modifierSurcharge = itemsModifierSurcharge(items);
98	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
99	  const discount = loyaltyDiscount(base, customer) + followUpDiscount(base, isFollowUp);
100	  return Math.ceil(base + modifierSurcharge + firstInsuranceSurcharge - discount + PROCESSING_FEE);
101	};
102	
103	const insuranceSum = (items: Item[]): number =>
104	  items.reduce((total, item) => total + unitInsuranceValue(item.type), 0);
105	
106	type Policy = { items: Item[]; capRemaining: number };
107	
108	const createPolicy = (items: Item[]): Policy => ({
109	  items,
110	  capRemaining: 2 * insuranceSum(items),
111	});
112	
113	const findDamagedItem = (policy: Policy, itemType: string): Item | undefined =>
114	  policy.items.find((item) => item.type === itemType);
115	
116	const reimbursableAmount = (item: Item | undefined, damage: DamageEntry): number =>
117	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
118	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
119	    : damage.amount;
120	
121	const damagePayout = (policy: Policy, damage: DamageEntry): number => {
122	  const item = findDamagedItem(policy, damage.itemType);
123	  return Math.max(0, reimbursableAmount(item, damage) - DEDUCTIBLE);
124	};
125	
126	const validateDamageCounts = (policy: Policy, damages: DamageEntry[]): void => {
127	  const insuredCounts = countByType(policy.items);
128	  const damageCounts = countBy(damages, (damage) => damage.itemType);
129	  for (const [type, count] of damageCounts) {
130	    if (count > (insuredCounts.get(type) ?? 0)) {
131	      throw new Error(`More damage entries for ${type} than insured`);
132	    }
133	  }
134	};
135	
136	const validateDamageAmounts = (damages: DamageEntry[]): void => {
137	  for (const damage of damages) {
138	    if (damage.amount < 0) throw new Error(`Negative damage amount for ${damage.itemType}`);
139	  }
140	};
141	
142	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
143	  validateDamageAmounts(incident.damages);
144	  validateDamageCounts(policy, incident.damages);
145	  const rawPayout = incident.damages.reduce(
146	    (total, damage) => total + damagePayout(policy, damage),
147	    0,
148	  );
149	  const payout = Math.min(rawPayout, policy.capRemaining);
150	  policy.capRemaining -= payout;
151	  return { payout: Math.floor(payout), remainingCap: policy.capRemaining };
152	};
153	
154	const priorQuoteCount = (steps: Step[], upTo: number): number =>
155	  steps.slice(0, upTo).filter((s) => s.op === "quote").length;
156	
157	const handleQuote = (
158	  step: QuoteStep,
159	  index: number,
160	  scenario: Scenario,
161	  policies: Map<number, Policy>,
162	): QuoteResult => {
163	  step.items.forEach((item) => assertKnownItemType(item.type));
164	  const isFollowUp = priorQuoteCount(scenario.steps, index) > 0;
165	  policies.set(index, createPolicy(step.items));
166	  return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
167	};
168	
169	const handleClaim = (step: ClaimStep, policies: Map<number, Policy>): ClaimResult => {
170	  const policy = policies.get(step.policy);
171	  if (!policy) throw new Error(`No policy at index ${step.policy}`);
172	  return processClaim(policy, step.incident);
173	};
174	
175	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
176	  const policies = new Map<number, Policy>();
177	  const results: StepResult[] = scenario.steps.map((step, index) =>
178	    step.op === "quote"
179	      ? handleQuote(step, index, scenario, policies)
180	      : handleClaim(step, policies),
181	  );
182	  return { results };
183	};
